+function extractClaudeTextContent(response: ClaudeResponse): string {
+  return response.content
+    .filter(
+      (block): block is { type: "text"; text: string } => block.type === "text",
+    )
+    .map((block) => block.text)
+    .join("\n")
+    .trim();
+}
