+        type: "tool_use";
+        id: string;
+        name: string;
+        input: Record<string, unknown>;
+      } => block.type === "tool_use",
+    )
+    .map((block) => ({
+      arguments: JSON.stringify(block.input),
+      callId: block.id,
+      name: block.name,
+    }));
+}
