      payloadJson: adjustmentEvents.payloadJson,
      createdAt: adjustmentEvents.createdAt,
    })
    .from(adjustmentEvents)
    .where(eq(adjustmentEvents.sessionId, sessionId))
    .orderBy(asc(adjustmentEvents.createdAt))
