import { z } from "zod";

import { roleSchema } from "./conversation.js";

export const adjustmentTargetFormatSchema = z.enum([
  "reader",
  "markdown",
  "handover",
  "json",
]);

export const adjustmentSessionStatusSchema = z.enum([
  "open",
  "applied",
  "discarded",
  "failed",
]);

export const formatRuleKindSchema = z.enum([
  "structure",
  "inline_semantics",
  "render",
  "export_profile",
  "clipboard",
]);

export const formatRuleScopeSchema = z.enum([
  "import_local",
  "format_profile",
  "workspace_global",
]);

export const formatRuleStatusSchema = z.enum([
  "draft",
  "active",
  "disabled",
  "rejected",
]);

export const adjustmentEventTypeSchema = z.enum([
  "session_created",
  "clarification_requested",
  "preview_generated",
  "preview_failed",
  "rule_applied",
  "rule_disabled",
  "rule_promoted",
  "session_discarded",
  "message_deleted",
  "round_deleted",
  "message_restored",
]);

export const adjustmentSelectionSchema = z.object({
  // Optional for backward compatibility with pre-blockId imports. New rules should always include blockId.
  blockId: z.string().optional(),
