              className="inline-flex items-center justify-center rounded-xl border border-border/80 bg-background px-4 py-2 text-sm font-medium text-foreground transition hover:bg-foreground/5"
              type="button"
              onClick={onClose}
            >
              {adjustmentLabels.cancel}
            </button>
            {showReply && !isLoading && onRejectLastChange != null ? (
              <Button
                variant="destructive-outline"
                type="button"
                onClick={onRejectLastChange}
              >
                {adjustmentLabels.discard}
              </Button>
            ) : null}
            <button
              data-testid="adjustment-send"
              className="inline-flex items-center justify-center rounded-xl bg-primary px-4 py-2 text-sm font-medium text-primary-foreground transition hover:opacity-95 disabled:cursor-not-allowed disabled:opacity-60"
              disabled={
                isLoading || isSubmitting || draftMessage.trim().length === 0
              }
              type="submit"
            >
              {isSubmitting
                ? adjustmentLabels.sendPending
                : adjustmentLabels.send}
            </button>
          </div>
        </form>
      </div>

      {agentLoopStatus.phase === "thinking" && (
        <div
          data-testid="agent-status-thinking"
          className="flex items-center gap-2 border-t border-border/80 px-4 py-2 text-xs text-muted-foreground"
        >
          <Loader2 className="h-3 w-3 animate-spin" />
          <span>{adjustmentLabels.agentThinking}</span>
        </div>
      )}

      {agentLoopStatus.phase === "applying" && (
        <div
          data-testid="agent-status-applying"
          className="flex items-center gap-2 border-t border-border/80 px-4 py-2 text-xs text-muted-foreground"
        >
          <Loader2 className="h-3 w-3 animate-spin" />
          <span>
            {adjustmentLabels.agentApplying(agentLoopStatus.iteration)}
          </span>
        </div>
      )}

      {agentLoopStatus.phase === "done" && lastAssistantMessage && (
        <div
          data-testid="scope-selection"
          className="border-t border-border/80 px-4 py-3"
        >
          <p className="mb-2 text-xs text-muted-foreground">
            {adjustmentLabels.scopeQuestion}
          </p>
          <div className="flex gap-2">
            <button
              className="rounded-lg bg-primary px-3 py-1.5 text-xs font-medium text-primary-foreground hover:bg-primary/90"
              type="button"
              onClick={() => onScopeSelect?.("global")}
            >
              {adjustmentLabels.scopeGlobal}
            </button>
            <button
              className="rounded-lg border border-border px-3 py-1.5 text-xs font-medium text-foreground hover:bg-accent"
              type="button"
              onClick={() => onScopeSelect?.("local")}
            >
              {adjustmentLabels.scopeLocal}
            </button>
          </div>
        </div>
      )}
    </div>
  );
});

export function AdjustmentPopover({
  anchor,
  containerRef,
  open,
  ...contentProps
}: AdjustmentPopoverProps) {
  const { refs, floatingStyles, isPositioned } = useFloating({
    open,
    placement: "top-start",
    middleware: [offset(12), flip({ padding: 16 }), shift({ padding: 16 })],
    whileElementsMounted: autoUpdate,
  });

  useLayoutEffect(() => {
    if (!anchor) return;
    refs.setPositionReference({
      getBoundingClientRect() {
        const container = containerRef.current;
        if (!container) {
          return {
            x: 0,
            y: 0,
            top: 0,
            left: 0,
            bottom: 0,
            right: 0,
            width: 0,
            height: 0,
          };
        }
        const cr = container.getBoundingClientRect();
        const scrollTop = container.scrollTop;
        const top = anchor.top - scrollTop + cr.top;
        const left = anchor.left + cr.left;
        return {
          x: left,
          y: top,
          top,
          left,
          bottom: top + anchor.height,
          right: left + anchor.width,
          width: anchor.width,
          height: anchor.height,
        };
      },
    });
  }, [anchor, containerRef, refs]);

  const visible = open && isPositioned;

  return (
    <div
      ref={refs.setFloating}
      data-testid={`adjustment-popover-${contentProps.view}`}
      className="z-50 w-[28rem] max-w-[calc(100vw-2rem)]"
      style={{
        ...floatingStyles,
        visibility: visible ? "visible" : "hidden",
        pointerEvents: visible ? "auto" : "none",
      }}
      aria-hidden={!visible}
    >
      <PopoverContent {...contentProps} />
    </div>
  );
}

