 26→type AdjustmentPopoverProps = {
 27→  agentLoopStatus: AgentLoopStatus;
 28→  anchor: FloatingAdjustmentAnchor | null;
 29→  containerRef: React.RefObject<HTMLElement | null>;
 30→  draftMessage: string;
