 45→function getLastAssistantMessage(
 46→  sessionDetail: AdjustmentSessionDetail | null,
 47→) {
 48→  return (
 49→    sessionDetail?.messages
 50→      .slice()
 51→      .reverse()
 52→      .find((message) => message.role === "assistant")?.content ?? null
 53→  );
 54→}
 55→
 56→/** Debounce loading indicator to avoid flashing the overlay for fast API responses. */
 57→const LOADING_DEBOUNCE_MS = 300;
 58→
 59→function useDebouncedLoading(isLoading: boolean) {
 60→  const [showLoading, setShowLoading] = useState(false);
 61→
 62→  useEffect(() => {
 63→    if (!isLoading) {
 64→      setShowLoading(false);
 65→      return;
 66→    }
 67→    const timer = setTimeout(() => setShowLoading(true), LOADING_DEBOUNCE_MS);
 68→    return () => clearTimeout(timer);
 69→  }, [isLoading]);
 70→
 71→  return showLoading;
 72→}
 73→
 74→// Isolated textarea — prevents re-renders from parent state changes (isLoading, sessionDetail)
 75→// from touching the textarea DOM node, which would cause a placeholder repaint.
 76→const DraftTextarea = memo(function DraftTextarea({
 77→  value,
 78→  placeholder,
 79→  onChangeRef,
 80→}: {
 81→  value: string;
 82→  placeholder: string;
 83→  onChangeRef: React.RefObject<(value: string) => void>;
 84→}) {
 85→  return (
 86→    <textarea
 87→      data-testid="adjustment-draft-message"
 88→      className="min-h-24 w-full rounded-2xl border border-border/80 bg-background px-3 py-3 text-sm text-foreground outline-none placeholder:text-muted-foreground focus:border-primary/50 focus:ring-2 focus:ring-primary/20"
 89→      placeholder={placeholder}
 90→      value={value}
 91→      onChange={(event) => onChangeRef.current?.(event.target.value)}
 92→    />
 93→  );
 94→});
 95→
 96→const PopoverContent = memo(function PopoverContent({
 97→  agentLoopStatus,
 98→  draftMessage,
 99→  error,
100→  isLoading,
101→  isSubmitting,
102→  onClose,
103→  onDraftMessageChange,
104→  onRejectLastChange,
105→  onScopeSelect,
106→  onSubmitMessage,
107→  sessionDetail,
108→  showReply,
109→  view: _view,
110→}: Omit<AdjustmentPopoverProps, "anchor" | "containerRef" | "open">) {
111→  const lastAssistantMessage = getLastAssistantMessage(sessionDetail);
112→  const showLoadingOverlay = useDebouncedLoading(isLoading);
113→
114→  const onChangeRef = useRef(onDraftMessageChange);
115→  onChangeRef.current = onDraftMessageChange;
116→
117→  const placeholder = showReply
118→    ? adjustmentLabels.followUpPlaceholder
119→    : adjustmentLabels.adjustmentPlaceholder;
120→
121→  return (
122→    <div className="overflow-hidden rounded-[1.4rem] border border-border bg-background shadow-[0_24px_80px_-32px_rgba(15,23,42,0.5)]">
123→      <div className="flex items-center justify-between gap-3 border-b border-border/80 px-4 py-3">
124→        <p className="text-[11px] font-semibold uppercase tracking-[0.2em] text-primary">
125→          {adjustmentLabels.createRuleLabel}
126→        </p>
127→        <button
128→          className="rounded-full p-1 text-muted-foreground transition hover:bg-foreground/5 hover:text-foreground"
129→          type="button"
130→          onClick={onClose}
131→        >
132→          <span className="sr-only">{adjustmentLabels.closeLabel}</span>
133→          <X className="h-4 w-4" />
134→        </button>
135→      </div>
136→
137→      <div className="relative overflow-y-auto px-4 py-4">
138→        {error ? (
139→          <div
140→            data-testid="adjustment-error"
141→            className="absolute inset-x-4 top-4 z-10 rounded-2xl border border-red-300/40 bg-red-100/70 px-3 py-3 text-sm text-red-900"
142→          >
143→            {error}
144→          </div>
145→        ) : null}
146→
147→        {showLoadingOverlay ? (
148→          <div className="absolute inset-x-4 top-4 z-10 rounded-2xl border border-border/80 bg-card/95 px-3 py-3 text-sm text-muted-foreground">
149→            {adjustmentLabels.loadingMessage}
150→          </div>
151→        ) : null}
152→
153→        {showReply && lastAssistantMessage ? (
154→          <div
155→            data-testid="adjustment-last-reply"
156→            className="mb-3 rounded-2xl border border-primary/20 bg-primary/5 px-3 py-3 text-sm text-foreground"
157→          >
158→            <p className="whitespace-pre-wrap">{lastAssistantMessage}</p>
159→          </div>
160→        ) : null}
161→
162→        <form className="space-y-3" onSubmit={onSubmitMessage}>
163→          {/* biome-ignore lint/a11y/noLabelWithoutControl: DraftTextarea contains a textarea */}
164→          <label className="block text-sm text-foreground">
165→            <span className="sr-only">{adjustmentLabels.inputLabel}</span>
166→            <DraftTextarea
167→              value={draftMessage}
168→              placeholder={placeholder}
